func isNoCache(cacheControl string) bool {
	i := strings.Index(cacheControl, noCacheValue)
	if i == -1 {
		return false
	}

	if i > 0 && !(cacheControl[i-1] == ' ' || cacheControl[i-1] == ',') {
		return false
	}

	if i+len(noCacheValue) == len(cacheControl) {
		return true
	}

	if cacheControl[i+len(noCacheValue)] != ',' {
		return false
	}

	return true
}
